import{_ as i,o as a,c as e,a2 as t}from"./chunks/framework.BflysNKA.js";const c=JSON.parse('{"title":"Windows 接入 Claude Code","description":"","frontmatter":{},"headers":[],"relativePath":"beginner/windows-claude-code.md","filePath":"beginner/windows-claude-code.md","lastUpdated":1780486201000}'),n={name:"beginner/windows-claude-code.md"};function l(p,s,d,h,r,o){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="windows-接入-claude-code" tabindex="-1">Windows 接入 Claude Code <a class="header-anchor" href="#windows-接入-claude-code" aria-label="Permalink to &quot;Windows 接入 Claude Code&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">前置条件</p><p>开始之前，确保你已经完成：</p><ol><li>✅ <a href="/beginner/windows-env">环境准备</a>（PowerShell 策略 + Git）</li><li>✅ 小蓝中转站 账号已注册并充值</li><li>✅ 已创建 API 密钥（以 <code>sk-</code> 开头的字符串）</li><li>✅ 已从模型广场复制模型名</li></ol><p>还没做？先回 <a href="/beginner/windows">Windows 快速接入</a> 的第一阶段。</p></div><h2 id="第-1-步-安装-claude-code" tabindex="-1">第 1 步：安装 Claude Code <a class="header-anchor" href="#第-1-步-安装-claude-code" aria-label="Permalink to &quot;第 1 步：安装 Claude Code&quot;">​</a></h2><p>打开 PowerShell（建议以管理员身份运行），选一种方式安装：</p><p><strong>方式一：官方脚本（推荐，不需要 Node.js）</strong></p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">claude.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> iex</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>方式二：WinGet</strong></p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">winget install Anthropic.ClaudeCode</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>方式三：npm（需要已安装 Node.js）</strong></p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm install </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">g @anthropic</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">claude</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">code</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>安装完成后，<strong>关闭 PowerShell，重新打开一个新窗口</strong>，验证：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">claude </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>应该输出版本号（如 <code>1.0.x</code>）。如果提示命令不存在，说明安装没成功或 PATH 没有更新，重新安装后再关闭终端重开。</p><h2 id="第-2-步-配置-xiaolan-网关" tabindex="-1">第 2 步：配置 小蓝中转站 网关 <a class="header-anchor" href="#第-2-步-配置-xiaolan-网关" aria-label="Permalink to &quot;第 2 步：配置 小蓝中转站 网关&quot;">​</a></h2><p>Claude Code 需要知道三样东西：地址、Key、是否开启模型发现。</p><p>在 PowerShell 里执行以下三条命令（把 <code>sk-你的专属Key</code> 替换成你在控制台创建的真实 Key）：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;ANTHROPIC_BASE_URL&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;https://xiaolan1.cn&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;ANTHROPIC_AUTH_TOKEN&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;sk-你的专属Key&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;1&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>每条命令的含义：</p><table tabindex="0"><thead><tr><th>变量</th><th>含义</th><th>注意</th></tr></thead><tbody><tr><td><code>ANTHROPIC_BASE_URL</code></td><td>小蓝中转站 网关地址</td><td><strong>只能写 <code>https://xiaolan1.cn</code>，不要加 <code>/v1</code></strong></td></tr><tr><td><code>ANTHROPIC_AUTH_TOKEN</code></td><td>你的 API Key</td><td>以 <code>sk-</code> 开头，从控制台复制</td></tr><tr><td><code>CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY</code></td><td>启动时自动发现可用模型</td><td>设为 <code>1</code> 开启</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">最常见的错误</p><p>Base URL <strong>不要</strong>写成 <code>https://xiaolan1.cn/v1</code>。Claude Code 会自己在后面拼接路径，你多写一个 <code>/v1</code> 会导致最终地址变成 <code>.../v1/v1/...</code>，报 404 错误。</p></div><p>设置完后，<strong>关闭 PowerShell，打开一个新的</strong>，验证环境变量是否生效：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">ANTHROPIC_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">ANTHROPIC_AUTH_TOKEN</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>应该分别输出 <code>https://xiaolan1.cn</code> 和你的 Key。如果输出为空，说明设置没成功。</p><h2 id="第-3-步-固定默认模型-可选" tabindex="-1">第 3 步：固定默认模型（可选） <a class="header-anchor" href="#第-3-步-固定默认模型-可选" aria-label="Permalink to &quot;第 3 步：固定默认模型（可选）&quot;">​</a></h2><p>如果你想让 Claude Code 每次启动都用同一个模型，可以设置：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;ANTHROPIC_MODEL&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;从模型广场复制的模型名&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>也可以不设置，启动后用 <code>/model</code> 命令手动选择。</p><h2 id="第-4-步-测试" tabindex="-1">第 4 步：测试 <a class="header-anchor" href="#第-4-步-测试" aria-label="Permalink to &quot;第 4 步：测试&quot;">​</a></h2><p>创建一个测试目录，启动 Claude Code：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">mkdir $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">USERPROFILE\\xiaolan</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">claude</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">test</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">cd $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">USERPROFILE\\xiaolan</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">claude</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">test</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">claude</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Claude Code 启动后，输入一句话（比如「你好」）。如果能收到回复，说明配置成功。</p><p><strong>如果弹出了官方登录界面</strong>，说明环境变量没有被正确读取。关闭 Claude Code，回到第 2 步重新检查。</p><p>配置成功后，你就可以在真实项目目录里使用 Claude Code 了：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">cd 你的项目目录</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">claude</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因</th><th>怎么处理</th></tr></thead><tbody><tr><td>弹出官方登录、连不上</td><td>环境变量没写入或没生效</td><td>重新执行第 2 步，关闭终端再开新的，用 <code>echo $env:ANTHROPIC_BASE_URL</code> 验证</td></tr><tr><td>报 404 错误</td><td>Base URL 多写了 <code>/v1</code></td><td>检查 <code>ANTHROPIC_BASE_URL</code> 必须是 <code>https://xiaolan1.cn</code>（不带 <code>/v1</code>）</td></tr><tr><td>启动后看不到模型列表</td><td>模型发现没开</td><td>确认 <code>CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY</code> 为 <code>1</code></td></tr><tr><td>Key 无效 / 鉴权失败</td><td>Key 被停用或余额不足</td><td>回控制台检查 Key 状态和余额</td></tr><tr><td>模型不存在</td><td>模型名写错了</td><td>回模型广场重新复制完整模型名，不要手动编</td></tr><tr><td><code>claude</code> 命令不存在</td><td>安装没成功或 PATH 未更新</td><td>重新安装后关闭终端重开</td></tr></tbody></table><p>遇到以上方法无法解决的问题，去 <a href="/support/troubleshooting">排障手册</a> 按层级排查。</p>`,37)])])}const u=i(n,[["render",l]]);export{c as __pageData,u as default};
